public long adjustOffset(long instant, boolean earlierOrLater) {
    // Get local times 4 hours before and after the current instant
    long localBefore = convertUTCToLocal(instant - 4 * DateTimeConstants.MILLIS_PER_HOUR);
    long localAfter = convertUTCToLocal(instant + 4 * DateTimeConstants.MILLIS_PER_HOUR);

    // Work out range of instants that have duplicate local times
    long local = convertUTCToLocal(instant);
    long instantBefore = convertLocalToUTC(local, false, localBefore);
    long instantAfter = convertLocalToUTC(local, false, localAfter);

    // Return the adjusted instant
    if (earlierOrLater) {
        return instantAfter;
    } else {
        return instantBefore;
    }
}
